#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <vector>
#include <iostream>
#include <cuda_runtime.h>

using namespace std;

// Type definitions from OpenCL headers
typedef struct {
    float lat;
    float lng;
} LatLong;

typedef struct {
    char recString[49];
    float distance;
} Record;

// CUDA Kernel equivalent to OpenCL NearestNeighbor
__global__ void NearestNeighbor(LatLong* d_locations,
                                float* d_distances,
                                const int numRecords,
                                const float lat,
                                const float lng) {
    int v_3 = threadIdx.x + blockIdx.x * blockDim.x;

    if (v_3 < numRecords) {
        LatLong* latLong = d_locations + v_3;
        float* v_0 = d_distances + v_3;
        *v_0 = sqrtf((lat - latLong->lat) * (lat - latLong->lat) + (lng - latLong->lng) * (lng - latLong->lng));
    }
}

// Utility functions to replace OpenCL utils
void* alloc(size_t size) {
    void* ptr = malloc(size);
    if (NULL == ptr) {
        perror("malloc");
        exit(-1);
    }
    return ptr;
}

int cuda_errChk(cudaError_t status, const char* msg, bool exitOnErr) {
    if (status != cudaSuccess) {
        printf("CUDA Error: %d %s %s\n", status, cudaGetErrorString(status), msg);
        if (exitOnErr) {
            exit(-1);
        }
        return true;
    }
    return false;
}

// Timing utilities (replacing OpenCL timing with CUDA events or gettimeofday)
#ifdef _WIN32
#include <windows.h>
#define DELTA_EPOCH_IN_MICROSECS  11644473600000000ULL
struct timezone {
    int tz_minuteswest;
    int tz_dsttime;
};

int gettimeofday(struct timeval* tv, struct timezone* tz) {
    FILETIME ft;
    unsigned __int64 tmpres = 0;
    static int tzflag = 0;

    if (tv != NULL) {
        GetSystemTimeAsFileTime(&ft);
        tmpres |= ft.dwHighDateTime;
        tmpres <<= 32;
        tmpres |= ft.dwLowDateTime;
        tmpres /= 10;
        tmpres -= DELTA_EPOCH_IN_MICROSECS;
        tv->tv_sec = (long)(tmpres / 1000000UL);
        tv->tv_usec = (long)(tmpres % 1000000UL);
    }
    if (tz != NULL) {
        if (!tzflag) {
            _tzset();
            tzflag++;
        }
        long seconds_diff;
        _get_timezone(&seconds_diff);
        tz->tz_minuteswest = seconds_diff / 60;
        int hours_offset;
        _get_daylight(&hours_offset);
        tz->tz_dsttime = hours_offset;
    }
    return 0;
}
#else
#include <sys/time.h>
#endif

void tvsub(struct timeval* t1, struct timeval* t2, struct timeval* result) {
    result->tv_sec = t1->tv_sec - t2->tv_sec;
    result->tv_usec = t1->tv_usec - t2->tv_usec;
    if (result->tv_usec < 0) {
        result->tv_sec--;
        result->tv_usec += 1000000;
    }
}

// Global variables for timing
#ifdef TIMING
struct timeval tv;
struct timeval tv_total_start, tv_total_end;
struct timeval tv_init_end;
struct timeval tv_h2d_start, tv_h2d_end;
struct timeval tv_d2h_start, tv_d2h_end;
struct timeval tv_kernel_start, tv_kernel_end;
struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
struct timeval tv_close_start, tv_close_end;
float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
      d2h_time = 0, close_time = 0, total_time = 0;
